import { NextResponse } from "next/server";
import { db } from "@/db";
import { styles, stylePages, styleVersions, corpusImages } from "@/db/schema";
import { eq, desc, asc, like, sql } from "drizzle-orm";
import { requireAuth } from "@/lib/auth";

function generateId(): string {
  return crypto.randomUUID().slice(0, 12);
}

function slugify(name: string): string {
  return name
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-|-$/g, "");
}

export async function GET(req: Request) {
  try {
    const url = new URL(req.url);
    const search = url.searchParams.get("search");
    const tag = url.searchParams.get("tag");
    const sort = url.searchParams.get("sort") || "recent";
    const page = parseInt(url.searchParams.get("page") || "1", 10);
    const limit = parseInt(url.searchParams.get("limit") || "20", 10);
    const offset = (page - 1) * limit;

    const conditions: ReturnType<typeof eq>[] = [];

    if (search) {
      conditions.push(like(styles.name, `%${search}%`));
    }
    if (tag) {
      conditions.push(sql`${styles.tags} like ${"%" + tag + "%"}`);
    }

    const orderBy =
      sort === "popular"
        ? desc(styles.likesCount)
        : sort === "name"
          ? asc(styles.name)
          : desc(styles.createdAt);

    const where =
      conditions.length > 0
        ? sql`${sql.join(conditions, sql` AND `)}`
        : undefined;

    const [rows, countResult] = await Promise.all([
      db
        .select({
          id: styles.id,
          name: styles.name,
          slug: styles.slug,
          description: styles.description,
          philosophy: styles.philosophy,
          authorName: styles.authorName,
          thumbnailUrl: styles.thumbnailUrl,
          previewHtml: styles.previewHtml,
          tags: styles.tags,
          likesCount: styles.likesCount,
          forksCount: styles.forksCount,
          forkedFromId: styles.forkedFromId,
          createdAt: styles.createdAt,
        })
        .from(styles)
        .where(where)
        .orderBy(orderBy)
        .limit(limit)
        .offset(offset),
      db
        .select({ count: sql<number>`count(*)` })
        .from(styles)
        .where(where),
    ]);

    return NextResponse.json({
      styles: rows,
      total: countResult[0].count,
    });
  } catch (error) {
    console.error("GET /api/styles error:", error);
    return NextResponse.json(
      { error: "Failed to fetch styles" },
      { status: 500 },
    );
  }
}

export async function POST(req: Request) {
  try {
    const { authorized } = requireAuth(req);
    if (!authorized) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    const body = await req.json();
    const {
      name,
      description,
      skillContent,
      authorName,
      authorUrl,
      tags,
      pages,
      corpusImages: images,
      skinCss,
    } = body;

    if (!name || !skillContent || !authorName) {
      return NextResponse.json(
        { error: "name, skillContent, and authorName are required" },
        { status: 400 },
      );
    }

    const id = generateId();
    const slug = slugify(name);
    const now = new Date().toISOString();

    const landingPage = pages?.find(
      (p: { pageType: string }) => p.pageType === "landing",
    );

    await db.insert(styles).values({
      id,
      name,
      slug,
      description: description || null,
      skillContent,
      authorName,
      authorUrl: authorUrl || null,
      tags: tags || null,
      previewHtml: landingPage?.htmlContent || null,
      thumbnailUrl: null,
      skinCss: skinCss || null,
      philosophy: null,
      likesCount: 0,
      forksCount: 0,
      forkedFromId: null,
      version: 1,
      createdAt: now,
      updatedAt: now,
    });

    // Create version 1
    await db.insert(styleVersions).values({
      id: generateId(),
      styleId: id,
      version: 1,
      skillContent,
      changelog: "Initial version",
      createdAt: now,
    });

    // Create pages
    if (pages?.length) {
      await db.insert(stylePages).values(
        pages.map((p: { pageType: string; htmlContent: string }) => ({
          id: generateId(),
          styleId: id,
          pageType: p.pageType,
          htmlContent: p.htmlContent,
          createdAt: now,
        })),
      );
    }

    // Create corpus images
    if (images?.length) {
      await db.insert(corpusImages).values(
        images.map(
          (img: { url: string; source?: string; caption?: string }) => ({
            id: generateId(),
            styleId: id,
            url: img.url,
            source: img.source || null,
            caption: img.caption || null,
            createdAt: now,
          }),
        ),
      );
    }

    const [created] = await db
      .select()
      .from(styles)
      .where(eq(styles.id, id));

    return NextResponse.json(created, { status: 201 });
  } catch (error) {
    console.error("POST /api/styles error:", error);
    return NextResponse.json(
      { error: "Failed to create style" },
      { status: 500 },
    );
  }
}
